const data = result?.data;

{result?.status === "success" && data && (
  <div>
    <h3>Train Size: {data.train_size}</h3>
    <h3>Test Size: {data.test_size}</h3>

    <tbody>
      {data?.y_test?.map((val, i) => (
        <tr key={i}>
          <td>{i}</td>
          <td>{val}</td>
        </tr>
      ))}
    </tbody>
  </div>
)}
